```

**ChannelMessagingAdapter (Optional but Recommended)**
```typescript
{
  normalizeTarget: (raw: string) => string;
  parseExplicitTarget: (raw: string) => { to: string; threadId?: string | number };
  formatTargetDisplay: (target: string, display?: string, kind?: string) => string;
  resolveOutboundSessionRoute: (params: {...}) => ChannelOutboundSessionRoute;
  // ... resolution helpers
}
```

