│   ├── targets.ts                # Target parsing
│   ├── probe.js                  # Health checking
│   └── ... (40+ support files)
```

---

### 10. **For Creating PulseBoard Plugin**

**Minimum Files Needed:**

1. `extensions/pulseboard/openclaw.plugin.json`
   ```json
   {
     "id": "pulseboard",
     "channels": ["pulseboard"],
