22	export type ResolvedInboundDirectDmAccess = {
23	  access: {
24	    decision: "allow" | "block" | "pairing";
25	    reasonCode: DmGroupAccessReasonCode;
26	    reason: string;
27	    effectiveAllowFrom: string[];
28	  };
29	  shouldComputeAuth: boolean;
30	  senderAllowedForCommands: boolean;
