export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin boards with named channels and direct messages.",
        order: 60,
      },
      capabilities: {
        chatTypes: ["direct", "group"],   // <-- supports both DMs and boards
