      },

      // Groups (boards) adapter — mirrors IRC's group adapter
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseBoardAccount({ cfg, accountId });
          // Boards require @mention by default unless groupPolicy is "open"
          return (account.config.groupPolicy ?? "allowlist") !== "open";
