### `extensions/pulseboard/src/channel.ts`

Main plugin. Uses `createChatChannelPlugin()` from `openclaw/plugin-sdk/core`.  
Template: Nostr for DMs + IRC for the `groups` adapter.

**Key structure:**

```typescript
export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin boards with named channels and direct messages.",
        order: 60,
      },
      capabilities: {
        chatTypes: ["direct", "group"],   // <-- supports both DMs and boards
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: pulseBoardChannelConfigSchema,
      setup: pulseBoardSetupAdapter,
      setupWizard: pulseBoardSetupWizard,
      config: {
        ...pulseBoardConfigAdapter,       // createTopLevelChannelConfigAdapter
        isConfigured: (account) => account.configured,
        describeAccount: (account) => describeAccountSnapshot({ account, configured: account.configured, extra: { serverUrl: account.serverUrl } }),
      },

      // Groups (boards) adapter — mirrors IRC's group adapter
      groups: {
        resolveRequireMention: ({ cfg, accountId, groupId }) => {
          const account = resolvePulseBoardAccount({ cfg, accountId });
          // Boards require @mention by default unless groupPolicy is "open"
          return (account.config.groupPolicy ?? "allowlist") !== "open";
        },
        resolveToolPolicy: () => undefined,
      },

      // Target normalization: "#board-name" for groups, "username" for DMs
      messaging: {
        normalizeTarget: (raw) => {
          const cleaned = raw.trim().replace(/^pulseboard:/i, "").toLowerCase();
          return cleaned;
        },
        targetResolver: {
          looksLikeId: (input) => /^[a-z0-9_#-]+$/i.test(input.trim()),
          hint: "<username|#board-name>",
        },
      },

      status: {
        // createComputedAccountStatusAdapter — mirrors Nostr's status block
      },

      // Stub gateway — real impl would open a WebSocket/SSE connection
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          if (!account.configured) {
            throw new Error("PulseBoard serverUrl and apiToken are required.");
          }
          ctx.log?.info(`[${account.accountId}] PulseBoard gateway started (${account.serverUrl})`);
          // Fictional: no real connection established
          return {
            stop: () => {
              ctx.log?.info(`[${account.accountId}] PulseBoard gateway stopped`);
            },
          };
        },
      },
    },

    pairing: {
      text: {
        idLabel: "pulseBoardUser",
        message: "Your pairing request has been approved!",
        normalizeAllowEntry: (entry) => entry.trim().toLowerCase().replace(/^pulseboard:/i, ""),
        notify: async ({ id, message }) => {
          // Fictional: would send a DM via PulseBoard API
          await sendPulseBoardMessage(id, message);
        },
      },
    },

    security: {
      resolveDmPolicy: createScopedDmSecurityResolver<ResolvedPulseBoardAccount>({
        channelKey: "pulseboard",
        resolvePolicy: (account) => account.config.dmPolicy,
        resolveAllowFrom: (account) => account.config.allowFrom,
        policyPathSuffix: "dmPolicy",
        defaultPolicy: "pairing",
        approveHint: 'Reply with "openclaw approve <id>" to approve a PulseBoard DM pairing.',
        normalizeEntry: (raw) => raw.trim().toLowerCase(),
      }),
    },

    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,             // PulseBoard spec: 4000 char limit
      sendText: async ({ cfg, to, text, accountId }) => {
        const account = resolvePulseBoardAccount({ cfg, accountId });
        return await sendPulseBoardMessage(to, text ?? "", {
          serverUrl: account.serverUrl,
          apiToken: account.apiToken,
          accountId: account.accountId,
        });
      },
    },
  });
```

