344	          onConnect: (relay) => {
345	            ctx.log?.debug?.(`[${account.accountId}] Connected to relay: ${relay}`);
346	          },
347	          onDisconnect: (relay) => {
348	            ctx.log?.debug?.(`[${account.accountId}] Disconnected from relay: ${relay}`);
349	          },
350	          onEose: (relays) => {
351	            ctx.log?.debug?.(`[${account.accountId}] EOSE received from relays: ${relays}`);
352	          },
353	          onMetric: (event: MetricEvent) => {
354	            // Log significant metrics at appropriate levels
355	            if (event.name.startsWith("event.rejected.")) {
356	              ctx.log?.debug?.(
357	                `[${account.accountId}] Metric: ${event.name} ${JSON.stringify(event.labels)}`,
358	              );
359	            } else if (event.name === "relay.circuit_breaker.open") {
