1	import fs from "node:fs";
2	import path from "node:path";
3	import { describe, expect, it } from "vitest";
4	
5	type PluginManifestShape = {
6	  id?: unknown;
7	};
8	
9	type OpenClawPackageShape = {
10	  name?: unknown;
11	  openclaw?: {
12	    install?: {
13	      npmSpec?: unknown;
14	    };
15	    channel?: {
16	      id?: unknown;
17	    };
18	  };
19	};
20	
21	type BundledPluginRecord = {
22	  dirName: string;
23	  packageName: string;
24	  manifestId: string;
25	  installNpmSpec?: string;
26	  channelId?: string;
27	};
28	
29	const EXTENSIONS_ROOT = path.resolve(process.cwd(), "extensions");
30	const DIR_ID_EXCEPTIONS = new Map<string, string>([
31	  // Historical directory name kept until a wider repo cleanup is worth the churn.
32	  ["kimi-coding", "kimi"],
33	]);
34	const ALLOWED_PACKAGE_SUFFIXES = [
35	  "",
36	  "-provider",
37	  "-plugin",
38	  "-speech",
39	  "-sandbox",
40	  "-media-understanding",
41	] as const;
42	
43	function readJsonFile<T>(filePath: string): T {
44	  return JSON.parse(fs.readFileSync(filePath, "utf8")) as T;
45	}
46	
47	function normalizeText(value: unknown): string | undefined {
48	  if (typeof value !== "string") {
49	    return undefined;
50	  }
51	  const trimmed = value.trim();
52	  return trimmed || undefined;
53	}
54	
55	function readBundledPluginRecords(): BundledPluginRecord[] {
56	  return fs
57	    .readdirSync(EXTENSIONS_ROOT)
58	    .toSorted()
59	    .flatMap((dirName) => {
60	      const rootDir = path.join(EXTENSIONS_ROOT, dirName);
61	      const packagePath = path.join(rootDir, "package.json");
62	      const manifestPath = path.join(rootDir, "openclaw.plugin.json");
63	      if (!fs.existsSync(packagePath) || !fs.existsSync(manifestPath)) {
64	        return [];
65	      }
66	
67	      const manifest = readJsonFile<PluginManifestShape>(manifestPath);
68	      const pkg = readJsonFile<OpenClawPackageShape>(packagePath);
69	      const manifestId = normalizeText(manifest.id);
70	      const packageName = normalizeText(pkg.name);
71	      if (!manifestId || !packageName) {
72	        return [];
73	      }
74	
75	      return [
76	        {
77	          dirName,
78	          packageName,
79	          manifestId,
80	          installNpmSpec: normalizeText(pkg.openclaw?.install?.npmSpec),
81	          channelId: normalizeText(pkg.openclaw?.channel?.id),
82	        },
83	      ];
84	    });
85	}
86	
87	function resolveAllowedPackageNamesForId(pluginId: string): string[] {
88	  return ALLOWED_PACKAGE_SUFFIXES.map((suffix) => `@openclaw/${pluginId}${suffix}`);
89	}
90	
91	function resolveBundledPluginMismatches(
92	  collectMismatches: (records: BundledPluginRecord[]) => string[],
93	) {
94	  return collectMismatches(readBundledPluginRecords());
95	}
96	
97	function expectNoBundledPluginNamingMismatches(params: {
98	  message: string;
99	  collectMismatches: (records: BundledPluginRecord[]) => string[];
100	}) {
101	  const mismatches = resolveBundledPluginMismatches(params.collectMismatches);
102	  expect(mismatches, `${params.message}\nFound: ${mismatches.join(", ") || "<none>"}`).toEqual([]);
103	}
104	
105	describe("bundled plugin naming guardrails", () => {
106	  it.each([
107	    {
108	      name: "keeps bundled workspace package names anchored to the plugin id",
109	      message: `Bundled extension package names must stay anchored to the manifest id via @openclaw/<id> or an approved suffix (${ALLOWED_PACKAGE_SUFFIXES.join(", ")}). Update the plugin naming docs and this invariant before adding a new naming form.`,
110	      collectMismatches: (records: BundledPluginRecord[]) =>
111	        records
112	          .filter(
113	            ({ packageName, manifestId }) =>
114	              !resolveAllowedPackageNamesForId(manifestId).includes(packageName),
115	          )
116	          .map(
117	            ({ dirName, packageName, manifestId }) =>
118	              `${dirName}: ${packageName} (id=${manifestId})`,
119	          ),
120	    },
121	    {
122	      name: "keeps bundled workspace directories aligned with the plugin id unless explicitly allowlisted",
123	      message:
124	        "Bundled extension directory names should match openclaw.plugin.json:id. If a legacy exception is unavoidable, add it to DIR_ID_EXCEPTIONS with a comment.",
125	      collectMismatches: (records: BundledPluginRecord[]) =>
126	        records
127	          .filter(
128	            ({ dirName, manifestId }) => (DIR_ID_EXCEPTIONS.get(dirName) ?? dirName) !== manifestId,
129	          )
130	          .map(({ dirName, manifestId }) => `${dirName} -> ${manifestId}`),
131	    },
132	    {
133	      name: "keeps bundled openclaw.install.npmSpec aligned with the package name",
134	      message:
135	        "Bundled openclaw.install.npmSpec values must match the package name so install/update paths stay deterministic.",
136	      collectMismatches: (records: BundledPluginRecord[]) =>
137	        records
138	          .filter(
139	            ({ installNpmSpec, packageName }) =>
140	              typeof installNpmSpec === "string" && installNpmSpec !== packageName,
141	          )
