import { describeAccountSnapshot } from "openclaw/plugin-sdk/account-helpers";
import {
  createScopedDmSecurityResolver,
  createTopLevelChannelConfigAdapter,
} from "openclaw/plugin-sdk/channel-config-helpers";
import { attachChannelToResult } from "openclaw/plugin-sdk/channel-send-result";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import {
  buildPassiveChannelStatusSummary,
  buildTrafficStatusSummary,
} from "openclaw/plugin-sdk/extension-shared";
import { createComputedAccountStatusAdapter } from "openclaw/plugin-sdk/status-helpers";
import {
  buildChannelConfigSchema,
  collectStatusIssuesFromLastError,
  createDefaultChannelRuntimeState,
  DEFAULT_ACCOUNT_ID,
  type ChannelPlugin,
} from "../runtime-api.js";
import { PulseboardConfigSchema } from "./config-schema.js";
import { getPulseboardRuntime } from "./runtime.js";
import { sendPulseboardMessage } from "./send.js";
import { pulseboardSetupAdapter, pulseboardSetupWizard } from "./setup-surface.js";
import {
  listPulseboardAccountIds,
  normalizePulseboardTarget,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
  type ResolvedPulseboardAccount,
} from "./types.js";

/** Normalize a username or board handle for use in allowlists. */
function normalizePulseboardAllowEntry(raw: string): string {
  return raw.trim().replace(/^pulseboard:/i, "").toLowerCase();
}

const resolvePulseboardDmPolicy = createScopedDmSecurityResolver<ResolvedPulseboardAccount>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
  normalizeEntry: normalizePulseboardAllowEntry,
});

const pulseboardConfigAdapter = createTopLevelChannelConfigAdapter<ResolvedPulseboardAccount>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseboardAccount({ cfg }),
  listAccountIds: listPulseboardAccountIds,
  defaultAccountId: resolveDefaultPulseboardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "serverUrl", "apiToken", "dmPolicy", "allowFrom", "groupPolicy"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom
      .map((entry) => normalizePulseboardAllowEntry(String(entry)))
      .filter(Boolean),
});

export const pulseboardPlugin: ChannelPlugin<ResolvedPulseboardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Real-time bulletin board messaging via PulseBoard boards and DMs",
        order: 110,
      },
      capabilities: {
        // Supports both direct messages (DMs) and group board channels.
        chatTypes: ["direct", "group"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      configSchema: buildChannelConfigSchema(PulseboardConfigSchema),
      setup: pulseboardSetupAdapter,
      setupWizard: pulseboardSetupWizard,
      config: {
        ...pulseboardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl || null,
            },
          }),
      },
      messaging: {
        normalizeTarget: (target) => normalizePulseboardTarget(target),
        targetResolver: {
          // A target is valid if it is a board (`#board-name`) or a bare username.
          looksLikeId: (input) => {
            const cleaned = normalizePulseboardTarget(input);
            return /^#[a-z0-9]/.test(cleaned) || /^[a-z0-9]/.test(cleaned);
          },
          hint: "<#board-name|username>",
        },
      },
      status: {
        ...createComputedAccountStatusAdapter<ResolvedPulseboardAccount>({
          defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
          collectStatusIssues: (accounts) =>
            collectStatusIssuesFromLastError("pulseboard", accounts),
          buildChannelSummary: ({ snapshot }) =>
            buildPassiveChannelStatusSummary(snapshot, {
              serverUrl: snapshot.serverUrl ?? null,
            }),
          resolveAccountSnapshot: ({ account, runtime }) => ({
            accountId: account.accountId,
            name: account.name,
            enabled: account.enabled,
            configured: account.configured,
            extra: {
              serverUrl: account.serverUrl || null,
              ...buildTrafficStatusSummary(runtime),
            },
          }),
        }),
      },
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          ctx.setStatus({
            accountId: account.accountId,
            serverUrl: account.serverUrl,
          });
          ctx.log?.info(
            `[pulseboard/${account.accountId}] starting PulseBoard gateway (server: ${account.serverUrl || "unconfigured"})`,
          );

          if (!account.configured) {
            throw new Error("PulseBoard server URL and API token are required");
          }

          ctx.log?.info(
            `[pulseboard/${account.accountId}] PulseBoard gateway started (stub — no real network)`,
          );

          // Return cleanup function.
          return {
            stop: () => {
              ctx.log?.info(`[pulseboard/${account.accountId}] PulseBoard gateway stopped`);
            },
          };
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseboardDmPolicy,
    },
    pairing: {
      text: {
        idLabel: "pulseboardUsername",
        message: "Your pairing request has been approved!",
        normalizeAllowEntry: normalizePulseboardAllowEntry,
        notify: async ({ id, message }) => {
          // Stub: in a real implementation this would send `message` as a DM to `id`.
          const runtime = getPulseboardRuntime();
          const cfg = runtime.config.loadConfig();
          const account = resolvePulseboardAccount({ cfg });
          ctx: {
            // Log the pairing notification for the stub implementation.
            void sendPulseboardMessage({
              accountId: account.accountId,
              serverUrl: account.serverUrl,
              to: id,
              text: message,
            }).catch(() => {
              // Best-effort pairing notification; ignore failures.
            });
          }
        },
      },
    },
    outbound: {
      deliveryMode: "direct",
      // PulseBoard supports up to 4 000 characters per message chunk.
      textChunkLimit: 4000,
      sendText: async ({ cfg, to, text, accountId }) => {
        const runtime = getPulseboardRuntime();
        const aid = accountId ?? DEFAULT_ACCOUNT_ID;
        const account = resolvePulseboardAccount({ cfg, accountId: aid });
        const tableMode = runtime.channel.text.resolveMarkdownTableMode({
          cfg,
          channel: "pulseboard",
          accountId: aid,
        });
        const message = runtime.channel.text.convertMarkdownTables(text ?? "", tableMode);
        const normalizedTo = normalizePulseboardTarget(to);
        return attachChannelToResult(
          "pulseboard",
          await sendPulseboardMessage({
            accountId: aid,
            serverUrl: account.serverUrl,
            to: normalizedTo,
            text: message,
          }),
        );
      },
    },
  });

