import { describe, expect, it } from "vitest";
import { pulseboardPlugin } from "./channel.js";
import {
  listPulseboardAccountIds,
  normalizePulseboardTarget,
  resolveDefaultPulseboardAccountId,
  resolvePulseboardAccount,
} from "./types.js";

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeConfiguredCfg(
  overrides: {
    serverUrl?: string;
    apiToken?: string;
    enabled?: boolean;
    name?: string;
    dmPolicy?: string;
    allowFrom?: string[];
    groupPolicy?: string;
  } = {},
) {
  return {
    channels: {
      pulseboard: {
        serverUrl: overrides.serverUrl ?? "https://pb.example.com",
        apiToken: overrides.apiToken ?? "tok_test",
        enabled: overrides.enabled,
        name: overrides.name,
        dmPolicy: overrides.dmPolicy,
        allowFrom: overrides.allowFrom,
        groupPolicy: overrides.groupPolicy,
      },
    },
  };
}

function requireLooksLikeId() {
  const fn = pulseboardPlugin.messaging?.targetResolver?.looksLikeId;
  if (!fn) throw new Error("pulseboardPlugin messaging.targetResolver.looksLikeId missing");
  return fn;
}

function requireNormalizeTarget() {
  const fn = pulseboardPlugin.messaging?.normalizeTarget;
  if (!fn) throw new Error("pulseboardPlugin messaging.normalizeTarget missing");
  return fn;
}

function requireResolveDmPolicy() {
  const fn = pulseboardPlugin.security?.resolveDmPolicy;
  if (!fn) throw new Error("pulseboardPlugin security.resolveDmPolicy missing");
  return fn;
}

function requirePairingNormalizer() {
  const fn = pulseboardPlugin.pairing?.normalizeAllowEntry;
  if (!fn) throw new Error("pulseboardPlugin pairing.normalizeAllowEntry missing");
  return fn;
}

// ---------------------------------------------------------------------------
// Plugin meta
// ---------------------------------------------------------------------------

describe("pulseboardPlugin meta", () => {
  it("has the correct id", () => {
    expect(pulseboardPlugin.id).toBe("pulseboard");
  });

  it("has required meta fields", () => {
    expect(pulseboardPlugin.meta.label).toBe("PulseBoard");
    expect(pulseboardPlugin.meta.docsPath).toBe("/channels/pulseboard");
    expect(pulseboardPlugin.meta.blurb).toContain("PulseBoard");
  });
});

// ---------------------------------------------------------------------------
// Capabilities
// ---------------------------------------------------------------------------

describe("pulseboardPlugin capabilities", () => {
  it("supports direct messages", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("direct");
  });

  it("supports group boards", () => {
    expect(pulseboardPlugin.capabilities.chatTypes).toContain("group");
  });

  it("does not support media", () => {
    expect(pulseboardPlugin.capabilities.media).toBe(false);
  });
});

// ---------------------------------------------------------------------------
// Outbound
// ---------------------------------------------------------------------------

describe("pulseboardPlugin outbound", () => {
  it("has direct delivery mode", () => {
    expect(pulseboardPlugin.outbound?.deliveryMode).toBe("direct");
  });

  it("has a 4000-character text chunk limit", () => {
    expect(pulseboardPlugin.outbound?.textChunkLimit).toBe(4000);
  });
});

// ---------------------------------------------------------------------------
// Messaging
// ---------------------------------------------------------------------------

describe("pulseboardPlugin messaging", () => {
  describe("looksLikeId", () => {
    it("recognizes a board target starting with #", () => {
      expect(requireLooksLikeId()("#general")).toBe(true);
    });

    it("recognizes a bare username", () => {
      expect(requireLooksLikeId()("alice")).toBe(true);
    });

    it("recognizes a pulseboard:-prefixed target", () => {
      // After normalization the prefix is stripped; the underlying value starts
      // with 'a' which matches a username pattern.
      expect(requireLooksLikeId()("pulseboard:alice")).toBe(true);
    });

    it("rejects empty string", () => {
      expect(requireLooksLikeId())("")).toBe(false);
    });
  });

  describe("normalizeTarget", () => {
    it("strips the pulseboard: prefix", () => {
      expect(requireNormalizeTarget()("pulseboard:alice")).toBe("alice");
    });

    it("lowercases the target", () => {
      expect(requireNormalizeTarget()("ALICE")).toBe("alice");
      expect(requireNormalizeTarget()("#GENERAL")).toBe("#general");
    });

    it("strips whitespace", () => {
      expect(requireNormalizeTarget())("  alice  ")).toBe("alice");
    });

    it("keeps the # prefix for board targets", () => {
      expect(requireNormalizeTarget()("#announcements")).toBe("#announcements");
    });
  });
});

// ---------------------------------------------------------------------------
// Pairing
// ---------------------------------------------------------------------------

describe("pulseboardPlugin pairing", () => {
  it("has the correct id label", () => {
    expect(pulseboardPlugin.pairing?.idLabel).toBe("pulseboardUsername");
  });

  it("normalizes pulseboard: prefixes in allow entries", () => {
    expect(requirePairingNormalizer()("pulseboard:alice")).toBe("alice");
    expect(requirePairingNormalizer()("  PULSEBOARD:Alice  ")).toBe("alice");
  });
});

// ---------------------------------------------------------------------------
// Security
// ---------------------------------------------------------------------------

describe("pulseboardPlugin security", () => {
  it("normalizes dm allowlist entries via the dm policy adapter", () => {
    const resolveDmPolicy = requireResolveDmPolicy();
    const cfg = makeConfiguredCfg({ dmPolicy: "allowlist", allowFrom: ["pulseboard:bob"] });
    const account = pulseboardPlugin.config.resolveAccount(cfg, "default");
    const result = resolveDmPolicy({ cfg, account });
    if (!result) throw new Error("resolveDmPolicy returned null");
    expect(result.policy).toBe("allowlist");
    expect(result.normalizeEntry?.("pulseboard:bob")).toBe("bob");
  });
});

// ---------------------------------------------------------------------------
// Status
// ---------------------------------------------------------------------------

describe("pulseboardPlugin status", () => {
  it("has a default runtime with the expected shape", () => {
    expect(pulseboardPlugin.status?.defaultRuntime).toMatchObject({
      accountId: "default",
      running: false,
      lastStartAt: null,
      lastStopAt: null,
      lastError: null,
    });
  });
});

// ---------------------------------------------------------------------------
// Config adapter
// ---------------------------------------------------------------------------

describe("pulseboardPlugin config adapter", () => {
  it("listAccountIds returns empty array when unconfigured", () => {
    expect(pulseboardPlugin.config.listAccountIds({ channels: {} })).toEqual([]);
  });

  it("listAccountIds returns ['default'] when configured", () => {
    const cfg = makeConfiguredCfg();
    expect(pulseboardPlugin.config.listAccountIds(cfg)).toContain("default");
  });
});

// ---------------------------------------------------------------------------
// Type helpers
// ---------------------------------------------------------------------------

describe("listPulseboardAccountIds", () => {
  it("returns empty when not configured", () => {
    expect(listPulseboardAccountIds({ channels: {} })).toEqual([]);
  });

  it("returns empty when serverUrl is present but apiToken is missing", () => {
    const cfg = { channels: { pulseboard: { serverUrl: "https://pb.example.com" } } };
    expect(listPulseboardAccountIds(cfg)).toEqual([]);
  });

  it("returns empty when apiToken is present but serverUrl is missing", () => {
    const cfg = { channels: { pulseboard: { apiToken: "tok" } } };
    expect(listPulseboardAccountIds(cfg)).toEqual([]);
  });

  it("returns ['default'] when both are configured", () => {
    expect(listPulseboardAccountIds(makeConfiguredCfg())).toEqual(["default"]);
  });
});

describe("resolveDefaultPulseboardAccountId", () => {
  it("returns 'default' for configured accounts", () => {
    expect(resolveDefaultPulseboardAccountId(makeConfiguredCfg())).toBe("default");
  });

  it("returns 'default' even when unconfigured", () => {
    expect(resolveDefaultPulseboardAccountId({ channels: {} })).toBe("default");
  });
});

describe("resolvePulseboardAccount", () => {
  it("resolves a configured account", () => {
    const cfg = makeConfiguredCfg({ name: "My Bot" });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.accountId).toBe("default");
    expect(account.name).toBe("My Bot");
    expect(account.enabled).toBe(true);
    expect(account.configured).toBe(true);
    expect(account.serverUrl).toBe("https://pb.example.com");
  });

  it("marks account as unconfigured when serverUrl is missing", () => {
    const cfg = { channels: { pulseboard: { apiToken: "tok" } } };
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("marks account as unconfigured when apiToken is missing", () => {
    const cfg = { channels: { pulseboard: { serverUrl: "https://pb.example.com" } } };
    const account = resolvePulseboardAccount({ cfg });
    expect(account.configured).toBe(false);
  });

  it("respects the enabled flag", () => {
    const cfg = makeConfiguredCfg({ enabled: false });
    expect(resolvePulseboardAccount({ cfg }).enabled).toBe(false);
  });

  it("preserves all config options", () => {
    const cfg = makeConfiguredCfg({
      dmPolicy: "allowlist",
      allowFrom: ["alice"],
      groupPolicy: "open",
    });
    const account = resolvePulseboardAccount({ cfg });
    expect(account.config.dmPolicy).toBe("allowlist");
    expect(account.config.allowFrom).toEqual(["alice"]);
    expect(account.config.groupPolicy).toBe("open");
  });
});

describe("normalizePulseboardTarget", () => {
  it("strips the pulseboard: prefix", () => {
    expect(normalizePulseboardTarget("pulseboard:alice")).toBe("alice");
  });

  it("lowercases board names", () => {
    expect(normalizePulseboardTarget("#GENERAL")).toBe("#general");
  });

  it("trims whitespace", () => {
    expect(normalizePulseboardTarget("  #dev  ")).toBe("#dev");
  });

  it("leaves bare usernames unchanged (modulo case/trim)", () => {
    expect(normalizePulseboardTarget("Bob")).toBe("bob");
  });
});

